 * SESSION ISOLATION + SERVER-RESTART DETECTION
 * ─────────────────────────────────────────────────────────────────────────────
 *
 * PROBLEM 1 — Multi-tab: localStorage is shared across all tabs.
 *   Fix: sessionStorage is the primary store (tab-scoped). localStorage is a
 *   single-tab-refresh fallback, validated with a cross-user ID check.
 *
 * PROBLEM 2 — Server restart (JWT is stateless):
 *   .NET JWT tokens remain cryptographically valid after a server restart
 *   because the signing key lives in config, not memory. So calling
 *   /validate always returns 200 — the server restart is invisible to the
 *   token check.
 *
 *   REAL FIX — store a server boot fingerprint at login time:
 *   At login we call GET /api/mongo/auth/server-boot (see note below) OR fall
 *   back to reading the HTTP `Date` response header from the login call itself
 *   and storing it as `serverDateAtLogin`.
 *
 *   On rehydration we call GET /api/mongo/auth/validate and read its `Date`
 *   header as `serverDateNow`. We also store the client clock at login
 *   (`clientTimeAtLogin`) and read it again on rehydration (`clientTimeNow`).
 *
 *   Logic:
 *     expectedServerElapsed = clientTimeNow - clientTimeAtLogin  (ms)
 *     actualServerElapsed   = serverDateNow - serverDateAtLogin  (ms)
 *
 *   If actualServerElapsed < expectedServerElapsed - TOLERANCE:
 *     The server's clock advanced LESS than the client's clock.
 *     This only happens if the server was DOWN for part of that period
 *     (restarted). Clear session → home page.
 *
 *   TOLERANCE is set to 60 000 ms (1 minute) to absorb NTP jitter, load
 *   spikes, and clock skew between client and server.
 *
 *   Additionally: if the server provides an X-Server-Boot-Id header (a Guid
 *   set once at process startup), we compare that directly — it is perfectly
 *   reliable and requires adding ~3 lines to the .NET middleware.
 * ─────────────────────────────────────────────────────────────────────────────
 */

const RESTART_TOLERANCE_MS = 60_000; // 1 minute — absorbs clock skew / slow restarts

// ── Storage helpers ──────────────────────────────────────────────────────────

const writeTabSession = (token, userData) => {
  sessionStorage.setItem('token', token);
  sessionStorage.setItem('user', JSON.stringify(userData));
};

const writeLocalHint = (token, userData) => {
  localStorage.setItem('token', token);
  localStorage.setItem('user', JSON.stringify(userData));
};

const clearAllSession = () => {
  ['token', 'user', 'cart', 'currentPage', 'serverDateAtLogin',
   'clientTimeAtLogin', 'serverBootId', 'tokenIat']
    .forEach(k => {
      sessionStorage.removeItem(k);
      localStorage.removeItem(k);
    });
};

/**
 * Store the "boot fingerprints" we need to detect a server restart later.
 * Call this immediately after a successful login API response.
 *
 * @param {Response} loginResponse  — the raw fetch/axios Response object
 *                                    (pass response.headers if using axios)
 * @param {Headers|Object} headers  — response headers from the login call
 */
const storeBootFingerprint = (headers) => {
  // Server Date header from the login response (RFC 7231 UTC string)
  const serverDate = (typeof headers?.get === 'function')
    ? headers.get('Date')                       // fetch Headers object
    : (headers?.['date'] || headers?.['Date']); // axios headers object

  const serverDateMs = serverDate ? new Date(serverDate).getTime() : null;
  const clientTimeMs = Date.now();

  if (serverDateMs) {
    sessionStorage.setItem('serverDateAtLogin', String(serverDateMs));
    localStorage.setItem('serverDateAtLogin',   String(serverDateMs));
  }
  sessionStorage.setItem('clientTimeAtLogin', String(clientTimeMs));
  localStorage.setItem('clientTimeAtLogin',   String(clientTimeMs));

  // X-Server-Boot-Id header (optional — requires backend to add it)
  const bootId = (typeof headers?.get === 'function')
    ? headers.get('X-Server-Boot-Id')
    : (headers?.['x-server-boot-id'] || null);

  if (bootId) {
    sessionStorage.setItem('serverBootId', bootId);
    localStorage.setItem('serverBootId',   bootId);
  }
};

/**
 * Check whether the server appears to have restarted since we logged in.
 * Returns { restarted: bool, reason: string }
 */
const detectServerRestart = async (token) => {
  let response;
  try {
    response = await fetch('/api/mongo/auth/validate', {
      method: 'GET',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });
  } catch (err) {
    // Network error = server is completely down
    return { restarted: true, reason: `Network error: ${err.message}` };
