  const currentBootId = response.headers.get('X-Server-Boot-Id');
  const storedBootId  = sessionStorage.getItem('serverBootId') || localStorage.getItem('serverBootId');

  if (currentBootId && storedBootId) {
    if (currentBootId !== storedBootId) {
      return { restarted: true, reason: `Boot ID changed: ${storedBootId} → ${currentBootId}` };
    }
    // Boot IDs match — definitely the same server process
    return { restarted: false, reason: 'Boot ID match' };
  }

  // ── Check 2: Clock-delta comparison (works without backend changes) ───────
  const serverDateAtLogin  = parseInt(sessionStorage.getItem('serverDateAtLogin')  || localStorage.getItem('serverDateAtLogin')  || '0', 10);
  const clientTimeAtLogin  = parseInt(sessionStorage.getItem('clientTimeAtLogin')  || localStorage.getItem('clientTimeAtLogin')  || '0', 10);

  if (serverDateAtLogin && clientTimeAtLogin) {
    const currentServerDateStr = response.headers.get('Date');
    const currentServerDateMs  = currentServerDateStr ? new Date(currentServerDateStr).getTime() : 0;
    const currentClientTimeMs  = Date.now();

    if (currentServerDateMs) {
      const serverElapsed = currentServerDateMs - serverDateAtLogin;  // how much time the server thinks passed
      const clientElapsed = currentClientTimeMs - clientTimeAtLogin;  // how much time actually passed

      // If the server's elapsed time is significantly LESS than the client's,
      // the server was offline for part of that period → it restarted.
      if (clientElapsed - serverElapsed > RESTART_TOLERANCE_MS) {
        return {
          restarted: true,
          reason: `Clock delta: server elapsed ${serverElapsed}ms, client elapsed ${clientElapsed}ms`
        };
      }
    }
  }

