  return { restarted: false, reason: 'All checks passed' };
};

// ── JWT helpers ──────────────────────────────────────────────────────────────

const extractUserIdFromToken = (token) => {
  try {
    if (!token) return null;
    const payload = JSON.parse(atob(token.split('.')[1]));
    return (
      payload.nameid ||
      payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] ||
      payload.sub ||
      payload.userId ||
      null
    );
  } catch {
    return null;
  }
};

// ── Tab-session resolver ─────────────────────────────────────────────────────

const resolveTabSession = () => {
  // Priority 1: sessionStorage (this tab's own session)
  const ssToken = sessionStorage.getItem('token');
  const ssUser  = sessionStorage.getItem('user');
  if (ssToken && ssUser) {
    try {
      return { token: ssToken, userData: JSON.parse(ssUser), source: 'session' };
    } catch {
      sessionStorage.removeItem('token');
      sessionStorage.removeItem('user');
    }
  }

  // Priority 2: localStorage (single-tab refresh fallback — cross-user validated)
  const lsToken = localStorage.getItem('token');
  const lsUser  = localStorage.getItem('user');
  if (!lsToken || !lsUser) return null;

  try {
    const userData    = JSON.parse(lsUser);
    const tokenUserId = extractUserIdFromToken(lsToken);
    const storedId    = String(userData.userId || userData.id || '');

    if (tokenUserId && storedId && String(tokenUserId) !== storedId) {
      console.warn(`⚠️ Cross-tab contamination blocked: token owner ≠ stored user`);
      return null;
    }

    return { token: lsToken, userData, source: 'local' };
  } catch {
    return null;
  }
};

// ── Hook ─────────────────────────────────────────────────────────────────────

export const useAuth = () => {
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);
  const [profileData, setProfileData] = useState({
    fullName: '',
    email: '',
    mobile: '',
    gender: '',
    addresses: []
  });
  const [isInitializing, setIsInitializing] = useState(true);

  // ── Session rehydration ──────────────────────────────────────────────────
  useEffect(() => {
    const restoreSession = async () => {
      try {
        const resolved = resolveTabSession();

        if (!resolved) {
          console.log('ℹ️ No stored session — showing home page');
          return;
        }

        const { token, userData, source } = resolved;

        // ── Server restart detection ─────────────────────────────────────
        console.log('🔍 Checking server session...');
        const { restarted, reason } = await detectServerRestart(token);

        if (restarted) {
          console.warn(`⚠️ Server restart detected (${reason}) — clearing session → home page`);
          clearAllSession();
          return;
        }

        console.log(`✅ Server session valid (${reason})`);

        // ── Restore user state ───────────────────────────────────────────
        const tokenUserId = extractUserIdFromToken(token);
        const finalUserId = tokenUserId || userData.userId || userData.id;

        if (!finalUserId) {
          console.warn('⚠️ Cannot resolve user ID — clearing session');
          clearAllSession();
          return;
        }

        const rehydratedUser = {
          ...userData,
          id: finalUserId,
          userId: finalUserId
        };

        // Promote localStorage session into sessionStorage for tab isolation
        if (source === 'local') {
          writeTabSession(token, rehydratedUser);
          console.log('📋 Promoted localStorage → sessionStorage for tab isolation');
        }

        setUser(rehydratedUser);
        console.log(`✅ Session rehydrated from ${source}Storage for: ${rehydratedUser.email}`);
      } catch (err) {
        console.error('❌ Session restore failed:', err);
        clearAllSession();
      } finally {
        setIsInitializing(false);
      }
    };

    restoreSession();
  }, []);

  // ── Login ────────────────────────────────────────────────────────────────
  const handleLogin = async (loginData, loginRole, setError, setLoading) => {
    setError('');
    setLoading(true);

    try {
      if (!loginData.email?.trim()) throw new Error('Email is required');
      if (!loginData.password)       throw new Error('Password is required');

      console.log('🔐 Attempting MongoDB login...');

      const response = await mongoAuthAPI.login(
        loginData.email.trim(),
        loginData.password
      );

      const data = response?.data;
      if (!data?.token) throw new Error('Authentication token not received from server');

      const userRole = String(data.role || '').trim();
      if (!userRole || (userRole !== 'Customer' && userRole !== 'Admin')) {
        throw new Error('Invalid user role received from server');
      }
      if (userRole !== loginRole) {
        throw new Error(
          `This account is registered as ${userRole}. Please select ${userRole} login.`
        );
      }

      const tokenUserId = extractUserIdFromToken(data.token);
      const finalUserId = tokenUserId || data.mongoUserId || data.userId || data.id;
      if (!finalUserId) throw new Error('User ID not found. Please contact support.');

      const userData = {
        ...data,
        role: userRole,
        userId: finalUserId,
        id: finalUserId,
        email: data.email
      };

      // Store session in both storages
      writeTabSession(data.token, userData);
      writeLocalHint(data.token, userData);

      // ── Store boot fingerprint so we can detect server restarts later ──
      // axios wraps the response — response.headers is a plain object
      storeBootFingerprint(response.headers);

      const userState = {
        id: finalUserId,
        userId: finalUserId,
        email: data.email || '',
        role: userRole,
        name: data.fullName || data.name || '',
        mobile: data.mobile || '',
        gender: data.gender || ''
      };

      setUser(userState);
      console.log('✅ Login successful');
      return userRole;
    } catch (err) {
      console.error('❌ Login error:', err);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  // ── Register ─────────────────────────────────────────────────────────────
  const handleRegister = async (registerData, loginRole, setError, setLoading) => {
    const { fullName, email, mobile, password, confirmPassword, gender } = registerData;

    if (!fullName?.trim())            throw new Error('Full name is required');
    if (!email?.trim())               throw new Error('Email is required');
    if (!mobile?.trim())              throw new Error('Mobile number is required');
    if (!password)                    throw new Error('Password is required');
    if (password !== confirmPassword) throw new Error('Passwords do not match');
    if (password.length < 6)         throw new Error('Password must be at least 6 characters');

    setLoading(true);
    setError('');

    try {
      console.log('📝 Attempting MongoDB registration...');

      const response = await mongoAuthAPI.register(
        fullName.trim(),
        email.trim(),
        mobile.trim(),
        password,
        gender
      );

      const data = response.data;
      if (!data.token) throw new Error('No token received from server');
      if (!data.role)  throw new Error('No role returned from server');

      const tokenUserId = extractUserIdFromToken(data.token);
      const finalUserId = tokenUserId || data.userId || data.id || data.mongoUserId;
      if (!finalUserId) throw new Error('User ID not found in token. Please contact support.');

      const userData = { ...data, userId: finalUserId, id: finalUserId };

      writeTabSession(data.token, userData);
      writeLocalHint(data.token, userData);
      storeBootFingerprint(response.headers);

      setUser({
        id: finalUserId,
        userId: finalUserId,
        email: data.email,
        role: data.role,
        name: data.fullName,
        mobile: data.mobile || mobile,
        gender: data.gender || gender
      });

      setProfileData({
        fullName: data.fullName || fullName,
        email: data.email || email,
        mobile: data.mobile || mobile,
        gender: data.gender || gender,
        addresses: []
      });

      console.log('✅ Registration successful');
      return true;
    } catch (err) {
      console.error('❌ Registration error:', err);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  // ── Logout ───────────────────────────────────────────────────────────────
  const handleLogout = () => {
    clearAllSession();
    setUser(null);
    setOrders([]);
    setProfileData({ fullName: '', email: '', mobile: '', gender: '', addresses: [] });
    console.log('✅ Logged out — all session storage cleared');
  };

  // ── Profile ──────────────────────────────────────────────────────────────
  const loadProfile = async () => {
    if (!user) return;
    try {
      console.log('📋 Loading profile data...');
      let addresses = [];
      try {
        if (typeof addressAPI?.getAll === 'function') {
          const addrRes = await addressAPI.getAll();
          addresses = Array.isArray(addrRes?.data)
            ? addrRes.data
            : addrRes?.data?.addresses || [];
        }
      } catch (err) {
        console.warn('⚠️ Could not fetch addresses:', err);
        addresses = [];
      }

      addresses = (addresses || []).map((a, index) => {
        const mongoId = a._id || a.id || a.Id || `addr_${index}`;
        return {
          id: mongoId,
          _id: mongoId,
          label: a.label || a.Label || (a.IsDefault ? 'Home' : 'Address'),
          AddressLine1: a.AddressLine1 || a.addressLine1 || '',
          AddressLine2: a.AddressLine2 || a.addressLine2 || '',
          City: a.City || a.city || '',
          State: a.State || a.state || '',
          PostalCode: a.PostalCode || a.postalCode || '',
          Country: a.Country || a.country || 'India',
          IsDefault: Boolean(a.IsDefault || a.isDefault)
        };
      });

      setProfileData(prev => ({ ...prev, addresses }));
      console.log('✅ Profile loaded with', addresses.length, 'addresses');
    } catch (err) {
      console.error('❌ Error loading profile:', err);
      setProfileData(prev => ({ ...prev, addresses: [] }));
    }
  };

  // ── Orders ───────────────────────────────────────────────────────────────
  const loadOrders = async () => {
    if (!user) return;
    try {
      console.log('📦 Loading orders...');
      const response = await ordersAPI.history();
      const ordersData = response?.data || [];
      setOrders(ordersData);
      console.log('✅ Orders loaded:', ordersData.length);
    } catch (err) {
      console.error('❌ Error loading orders:', err);
      setOrders([]);
    }
  };

  return {
    user,
    setUser,
    orders,
    setOrders,
    profileData,
    setProfileData,
    isInitializing,
    handleLogin,
    handleRegister,
    handleLogout,
    loadProfile,
    loadOrders
  };
};
